// 親クラスEmployeeを作成
public class Employee {
    protected int salary;
    public Employee(int salary) {
        this.salary = salary;
    }
}

// Employeeクラスを継承したManagerクラスを作成
public class Manager extends Employee {
    private int bonus;
    public Manager(int salary, int bonus) {
        super(salary); // 親クラスのコンストラクタを呼び出してsalaryを設定
        this.bonus = bonus; // Managerクラスのフィールドbonusを設定
    }
}
```
// Managerクラスのインスタンスを作成し、salaryとbonusを設定できます。

